public static void main(Args _args)
{
    ETGLedgerVoucherExportController controller;

    controller = new ETGLedgerVoucherExportController(
        classStr(ETGLedgerVoucherExportService),
        methodStr(ETGLedgerVoucherExportService, processReport),
        SysOperationExecutionMode::Synchronous);

    controller.parmLoadFromSysLastValue(false);
    controller.parmArgs(_args);
    controller.parmDialogCaption("Load Ledger Data for Power BI");
    controller.parmShowDialog(true);
    controller.startOperation();
}

protected void new(
    IdentifierName _className,
    IdentifierName _methodName,
    SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    super(_className, _methodName, _executionMode);
}
